```typescript
detectCarrier(tracking_number: string): CarrierCode {
  const num = tracking_number.replace(/\s/g, '').toUpperCase();

  // Check most specific patterns first
  if (/^1Z[A-Z0-9]{16}$/i.test(num)) return 'ups'; // UPS: 1Z + 16 alphanumeric
  if (/^(94|93|92|91|90)\d{18,22}$/.test(num) || /^\d{20,22}$/.test(num)) return 'usps'; // USPS: 20-22 digits
  if (/^\d{15}$/.test(num)) return 'fedex'; // FedEx: 15 digits (most common)
  if (/^\d{12}$/.test(num)) return 'fedex'; // FedEx: 12 digits also valid
  if (/^\d{11}$/.test(num) || /^\d{13}$/.test(num)) return 'dhl'; // DHL: 11 or 13 digits

  return 'other';
}
