CREATE OR REPLACE FUNCTION auto_update_tier()
RETURNS TRIGGER AS $$
BEGIN
  -- Only recalculate if GMV or content count changed
  IF NEW.monthly_gmv <> OLD.monthly_gmv OR NEW.monthly_content_count <> OLD.monthly_content_count THEN
    IF NEW.monthly_gmv >= 5000 THEN
      NEW.tier = 'diamond';
      NEW.commission_rate = 40;
    ELSIF NEW.monthly_gmv >= 1000 THEN
      NEW.tier = 'gold';
      NEW.commission_rate = 40;
    ELSIF NEW.monthly_content_count >= 5 THEN
      NEW.tier = 'silver';
      NEW.commission_rate = 35;
    ELSE
      NEW.tier = 'bronze';
      NEW.commission_rate = 30;
    END IF;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;
